import { db } from "@/lib/db";
import { NextResponse } from "next/server";

export async function POST(req: Request) {
    try {
      const { email } = await req.json();
      const otp = Math.floor(1000 + Math.random() * 9000).toString();
      const otpExpiresAt = new Date(Date.now() + 10 * 60 * 1000); // OTP expires in 10 min
  
      const [users] = await db.query("SELECT id FROM users WHERE email = ?", [email]);
      if ((users as any[]).length === 0) {
        return NextResponse.json({ error: "Email not registered" }, { status: 400 });
      }
  
      await db.query("UPDATE users SET otp = ?, otp_expires_at = ? WHERE email = ?", [otp, otpExpiresAt, email]);
  
      return NextResponse.json({ message: "OTP resent successfully", otp }, { status: 200 }); // OTP in response for testing
  
    } catch (error) {
      console.error(error);
      return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
    }
  }
  